class Solution(object):
    def minimumArea(self, grid):
        m, n = len(grid), len(grid[0])
        min_r = min_c = float('inf')
        max_r = max_c = float('-inf')
        for r in range(m):
            for c in range(n):
                if grid[r][c] == 1:
                    min_r = min(min_r, r)
                    max_r = max(max_r, r)
                    min_c = min(min_c, c)
                    max_c = max(max_c, c)
        return (max_r - min_r + 1) * (max_c - min_c + 1)
